example.code:
import json
from pathlib import Path

def validate_jsonl(path: str, required_roles: tuple = ("user", "assistant")) -> None:
    """Validate fine-tuning dataset format before training."""
    errors = []
    with open(path) as f:
        for i, line in enumerate(f, 1):
            line = line.strip()
            if not line:
                continue
            try:
                obj = json.loads(line)
            except json.JSONDecodeError as e:
                errors.append(f"Line {i}: invalid JSON: {e}")
                continue

            if "messages" not in obj:
                errors.append(f"Line {i}: missing 'messages' key")
                continue

            roles = [m.get("role") for m in obj["messages"]]
            for role in required_roles:
                if role not in roles:
                    errors.append(f"Line {i}: missing required role '{role}'")

            for j, msg in enumerate(obj["messages"]):
                if not msg.get("content", "").strip():
                    errors.append(f"Line {i}, message {j}: empty content")

    if errors:
        raise ValueError(f"Dataset validation failed:\n" + "\n".join(errors[:20]))

{
  "messages": [
    {
      "role": "system",
      "content": "You are a customer support agent for Acme Corp. Answer questions about products and policies."
    },
    {
      "role": "user",
      "content": "What is your return policy?"
    },
    {
      "role": "assistant",
      "content": "Our return policy allows returns within 30 days of purchase with original receipt. Items must be unused and in original packaging. Contact support@acme.com to initiate a return."
    }
  ]
}

